INSERT INTO "products" VALUES(1,'Shop','shop','','','Renewal & Replacement Parts','','','','','["/images/products/shop/0.jpg"]','https://www.circuitbreaker.com/shop/','','','','','Shop. Available from Circuit Breaker Sales — industrial power equipment since 1993.',replace('<h3>Product Overview</h3>\n<p>The Shop is a renewal & replacement parts component manufactured by Leading manufacturer. This unit is available from Circuit Breaker Sales'' extensive inventory of industrial power distribution equipment.</p>\n<h3>Applications</h3>\n<p>Renewal and replacement parts keep existing electrical equipment operating safely and reliably, extending its service life and avoiding costly full replacements. Our inventory includes OEM and compatible aftermarket parts for all major manufacturers.</p>\n<h3>Why Circuit Breaker Sales?</h3>\n<p>As one of the largest independent stocking distributors of power distribution equipment in North America, Circuit Breaker Sales (a Group CBS company) carries an extensive inventory of new, reconditioned, and remanufactured renewal & replacement parts. Every piece of equipment is thoroughly inspected and tested before shipment to ensure safe, reliable operation.</p>\n<p>Contact our engineering team at 800-232-5809 for pricing, availability, and technical support.</p>','\n',char(10)),'["renewal & replacement parts"]','','','');
INSERT INTO "products" VALUES(2,'AKU-2A-50 EO/DO Circuit Breaker','aku-2a-50-eo-do-circuit-breaker','','<p><strong>Category:</strong> <a href="https://www.circuitbreaker.com/low-and-medium-voltage-circuit-breakers/" target="_blank" rel="noopener">Low-Voltage Circuit Breakers</a></p> <p>&nbsp;</p> <table width="100%"> <tbody> <tr> <th>Part/Catalog Number</th> <td>AKU-2A-50 EO/DO</td> </tr> <tr> <th>Original Manufacturer</th> <td><a href="https://www.circuitbreaker.com/general-electric-ge-circuit-breakers/" target="_blank" rel="noopener">General Electric (GE)</a></td> </tr> <tr> <th>Product Line</th> <td>AKU</td> </tr> <tr> <th>Amps</th> <td>1600 A Frame</td> </tr> <tr> <th>Operation</th> <td>Electrically Operated (Stored Energy)</td> </tr> <tr> <th>Mounting</th> <td>Draw-out</td> </tr> <tr> <th>Voltage</th> <td>600 V Class</td> </tr> <tr> <th>Interrupting Capacity</th> <td>200 kAIC (Fused)</td> </tr> </tbody> </table>','Circuit Breakers','','','','','["/images/products/aku-2a-50-eo-do-circuit-breaker/0.png","/images/products/aku-2a-50-eo-do-circuit-breaker/1.png"]','https://www.circuitbreaker.com/products-feed/aku-2a-50-eo-do-circuit-breaker/','Low Voltage','600 V','1600A','Circuit Breaker','low voltage circuit breaker. Tested, certified, and available from one of the largest independent inventories in North America.',replace('<h3>Product Overview</h3>\n<p>The AKU-2A-50 EO/DO Circuit Breaker is a circuit breakers component manufactured by Leading manufacturer. Category: Low-Voltage Circuit Breakers &nbsp;    Part/Catalog Number AKU-2A-50 EO/DO   Original Manufacturer General Electric (GE)   Product Line AKU   Amps 1600 A Frame   Operation Electrically Operated (Stored Energy)   Mounting Draw-out   Voltage 600 V Class   Interrupting Capacity 200 kAIC (Fused). This unit is available from Circuit Breaker Sales'' extensive inventory of industrial power distribution equipment.</p>\n<h3>Technical Specifications</h3>\n<ul>\n<li><strong>Voltage Rating:</strong> 600 V</li>\n<li><strong>Amperage Rating:</strong> 1600A</li>\n<li><strong>Manufacturer:</strong> Leading manufacturer</li>\n<li><strong>Type:</strong> Low Voltage</li>\n</ul>\n<h3>Applications</h3>\n<p>Circuit breakers are essential protective devices used in electrical power distribution systems to automatically interrupt current flow during overload or fault conditions. They are found in utility substations, industrial facilities, commercial buildings, data centers, and hospitals.</p>\n<h3>Why Circuit Breaker Sales?</h3>\n<p>As one of the largest independent stocking distributors of power distribution equipment in North America, Circuit Breaker Sales (a Group CBS company) carries an extensive inventory of new, reconditioned, and remanufactured circuit breakers. Every piece of equipment is thoroughly inspected and tested before shipment to ensure safe, reliable operation.</p>\n<p>Contact our engineering team at 800-232-5809 for pricing, availability, and technical support.</p>','\n',char(10)),'["circuit breakers","low voltage","breaker"]','','','');
