INSERT INTO "products" VALUES(588,'USD-3IR','usd-3ir','USD-3IR','<p><strong>Model:</strong> USD-31R</p> <p>Overcurrent Relay</p>','Protective Relays','Federal Pioneer','USD-31R','','','["/images/products/usd-3ir/0.jpg"]','https://www.circuitbreaker.com/circuit-breakers/usd-3ir/','Overcurrent','','','','Federal Pioneer USD-3IR. Model: USD-31R Overcurrent Relay. Available from Circuit Breaker Sales — industrial power equipment since 1993.',replace('<h3>Product Overview</h3>\n<p>The USD-3IR is a protective relays component manufactured by Federal Pioneer. Model: USD-31R Overcurrent Relay. This unit is available from Circuit Breaker Sales'' extensive inventory of industrial power distribution equipment.</p>\n<h3>Technical Specifications</h3>\n<ul>\n<li><strong>Part Number / SKU:</strong> USD-3IR</li>\n<li><strong>Model:</strong> USD-31R</li>\n<li><strong>Manufacturer:</strong> Federal Pioneer</li>\n<li><strong>Type:</strong> Overcurrent</li>\n</ul>\n<h3>Applications</h3>\n<p>Protective relays monitor electrical quantities (current, voltage, frequency) and initiate tripping of circuit breakers when abnormal conditions are detected. They are the backbone of power system protection, safeguarding equipment from damage due to faults, overloads, and other disturbances.</p>\n<h3>Why Circuit Breaker Sales?</h3>\n<p>As one of the largest independent stocking distributors of power distribution equipment in North America, Circuit Breaker Sales (a Group CBS company) carries an extensive inventory of new, reconditioned, and remanufactured protective relays. Every piece of equipment is thoroughly inspected and tested before shipment to ensure safe, reliable operation.</p>\n<p>Contact our engineering team at 800-232-5809 for pricing, availability, and technical support.</p>','\n',char(10)),'["protective relays","overcurrent","federal pioneer","usd-31r"]','','','');
