INSERT INTO "products" VALUES(692,'HSSA – 6','hssa-6','HSSA - 6','<p><strong>Model:</strong> HSSA – 6</p> <p>Overcurrent relay</p>','Protective Relays','Federal Pacific','HSSA – 6','','','["/images/products/hssa-6/0.jpg","/images/products/hssa-6/1.jpg"]','https://www.circuitbreaker.com/circuit-breakers/hssa-6/','Overcurrent','','','','Federal Pacific HSSA – 6. Model: HSSA – 6 Overcurrent relay. Available from Circuit Breaker Sales — industrial power equipment since 1993.',replace('<h3>Product Overview</h3>\n<p>The HSSA – 6 is a protective relays component manufactured by Federal Pacific. Model: HSSA – 6 Overcurrent relay. This unit is available from Circuit Breaker Sales'' extensive inventory of industrial power distribution equipment.</p>\n<h3>Technical Specifications</h3>\n<ul>\n<li><strong>Part Number / SKU:</strong> HSSA - 6</li>\n<li><strong>Model:</strong> HSSA – 6</li>\n<li><strong>Manufacturer:</strong> Federal Pacific</li>\n<li><strong>Type:</strong> Overcurrent</li>\n</ul>\n<h3>Applications</h3>\n<p>Protective relays monitor electrical quantities (current, voltage, frequency) and initiate tripping of circuit breakers when abnormal conditions are detected. They are the backbone of power system protection, safeguarding equipment from damage due to faults, overloads, and other disturbances.</p>\n<h3>Why Circuit Breaker Sales?</h3>\n<p>As one of the largest independent stocking distributors of power distribution equipment in North America, Circuit Breaker Sales (a Group CBS company) carries an extensive inventory of new, reconditioned, and remanufactured protective relays. Every piece of equipment is thoroughly inspected and tested before shipment to ensure safe, reliable operation.</p>\n<p>Contact our engineering team at 800-232-5809 for pricing, availability, and technical support.</p>','\n',char(10)),'["protective relays","overcurrent","federal pacific","hssa – 6"]','','','');
