INSERT INTO "products" VALUES(737,'RVQ','rvq','RVQ','<p><strong>Model:</strong> RVQ</p> <p>Power factor regulator</p>','Capacitor Banks','ABB','RVQ','','','["/images/products/rvq/0.jpg"]','https://www.circuitbreaker.com/circuit-breakers/rvq/','Power Factor Correction','','','','ABB RVQ. Model: RVQ Power factor regulator. Available from Circuit Breaker Sales — industrial power equipment since 1993.',replace('<h3>Product Overview</h3>\n<p>The RVQ is a capacitor banks component manufactured by ABB. Model: RVQ Power factor regulator. This unit is available from Circuit Breaker Sales'' extensive inventory of industrial power distribution equipment.</p>\n<h3>Technical Specifications</h3>\n<ul>\n<li><strong>Part Number / SKU:</strong> RVQ</li>\n<li><strong>Model:</strong> RVQ</li>\n<li><strong>Manufacturer:</strong> ABB</li>\n<li><strong>Type:</strong> Power Factor Correction</li>\n</ul>\n<h3>Applications</h3>\n<p>Capacitor banks are used for power factor correction and voltage support in industrial and utility power systems. Improving power factor reduces energy costs, improves voltage regulation, and increases available system capacity.</p>\n<h3>Why Circuit Breaker Sales?</h3>\n<p>As one of the largest independent stocking distributors of power distribution equipment in North America, Circuit Breaker Sales (a Group CBS company) carries an extensive inventory of new, reconditioned, and remanufactured capacitor banks. Every piece of equipment is thoroughly inspected and tested before shipment to ensure safe, reliable operation.</p>\n<p>Contact our engineering team at 800-232-5809 for pricing, availability, and technical support.</p>','\n',char(10)),'["capacitor banks","power factor correction","abb","rvq"]','','','');
