INSERT INTO "products" VALUES(923,'9441','9441','9441','<p><strong>Model:</strong> Current Transformer</p> <p>175/225/5A Current Transformer</p>','Transformers','Joslyn Hi-Voltage Corp','Current Transformer','','','["/images/products/9441/0.jpg","/images/products/9441/1.jpg","/images/products/9441/2.jpg"]','https://www.circuitbreaker.com/circuit-breakers/9441/','Instrument Transformers','','175/225/5A','Current Transformer','Joslyn Hi-Voltage Corp 175/225/5A instrument transformer Current Transformer. Available with warranty from Circuit Breaker Sales.',replace('<h3>Product Overview</h3>\n<p>The 9441 is a transformers component manufactured by Joslyn Hi-Voltage Corp. Model: Current Transformer 175/225/5A Current Transformer. This unit is available from Circuit Breaker Sales'' extensive inventory of industrial power distribution equipment.</p>\n<h3>Technical Specifications</h3>\n<ul>\n<li><strong>Part Number / SKU:</strong> 9441</li>\n<li><strong>Model:</strong> Current Transformer</li>\n<li><strong>Amperage Rating:</strong> 175/225/5A</li>\n<li><strong>Manufacturer:</strong> Joslyn Hi-Voltage Corp</li>\n<li><strong>Type:</strong> Instrument Transformers</li>\n</ul>\n<h3>Applications</h3>\n<p>Instrument transformers (current transformers and potential transformers) are used to step down high voltages and currents to safe, measurable levels for metering, protection, and control in power systems. They are essential in substations, switchgear, and protective relay schemes.</p>\n<h3>Why Circuit Breaker Sales?</h3>\n<p>As one of the largest independent stocking distributors of power distribution equipment in North America, Circuit Breaker Sales (a Group CBS company) carries an extensive inventory of new, reconditioned, and remanufactured transformers. Every piece of equipment is thoroughly inspected and tested before shipment to ensure safe, reliable operation.</p>\n<p>Contact our engineering team at 800-232-5809 for pricing, availability, and technical support.</p>','\n',char(10)),'["transformers","instrument transformers","joslyn hi-voltage corp","current transformer"]','','','');
