INSERT INTO "products" VALUES(1013,'ASCO 1200A Manual (MTS) Transfer Switch 480V','asco-1200a-manual-mts-transfer-switch-480v','TS-ASC-1200-x8p9','','Transfer Switches','ASCO','ASTS-1200','New Surplus','','["/images/products/asco-1200a-manual-mts-transfer-switch-480v/0.jpg"]','','Manual','480V','1200A','Transfer Switch','ASCO 1200A manual (mts) transfer switch rated at 480V. Ensures critical power continuity during utility outages. Available with warranty.','<h3>Product Overview</h3><p>The ASCO 1200A Manual (MTS) Transfer Switch 480V provides reliable automatic or manual transfer of electrical loads between primary and backup power sources. Manufactured by ASCO, this 1200-amp unit is designed for critical power applications including hospitals, data centers, and industrial facilities.</p><h3>Technical Specifications</h3><ul><li><strong>Amperage:</strong> 1200A</li><li><strong>Voltage:</strong> 480V</li><li><strong>Type:</strong> Manual (MTS)</li><li><strong>Manufacturer:</strong> ASCO</li></ul><h3>Applications</h3><p>Transfer switches are essential components of emergency and standby power systems. They automatically or manually transfer electrical loads between utility power and generator or UPS sources during power outages, ensuring uninterrupted operation of critical equipment.</p><h3>Why Circuit Breaker Sales?</h3><p>Circuit Breaker Sales maintains one of the largest independently-owned inventories of transfer switches in North America. Every unit is thoroughly inspected and tested before shipment. Contact us at 800-232-5809 for pricing and availability.</p>','["transfer switch","manual (mts)","asco","1200a","480v","emergency power","backup power"]','','','');
