INSERT INTO "products" VALUES(1037,'Eaton 300kA Type 1+2 Surge Protective Device 208Y/120V','eaton-300ka-type-1-2-surge-protective-device-208y-120v','SPD-EAT-300-x8p9','','Surge Protection','Eaton','SPD-300','New','','["/images/products/eaton-300ka-type-1-2-surge-protective-device-208y-120v/0.png"]','','SPDs','208Y/120V','','Surge Protective Device','Eaton 300kA Type 1+2 surge protective device rated for 208Y/120V systems. Protects sensitive equipment from transient overvoltages.','<h3>Product Overview</h3><p>The Eaton 300kA Type 1+2 Surge Protective Device 208Y/120V provides industry-leading surge protection for electrical distribution systems. With a 300kA surge current rating, this Type 1+2 device protects against lightning strikes, utility switching events, and internally generated transients.</p><h3>Technical Specifications</h3><ul><li><strong>Surge Rating:</strong> 300kA</li><li><strong>Voltage:</strong> 208Y/120V</li><li><strong>Type:</strong> Type 1+2</li><li><strong>Manufacturer:</strong> Eaton</li></ul><h3>Applications</h3><p>SPDs are installed at service entrances, distribution panels, and at the point of use to protect sensitive electronic equipment from voltage spikes and transients. Essential for data centers, hospitals, industrial controls, and any facility with sensitive equipment.</p><h3>Why Circuit Breaker Sales?</h3><p>We carry a wide selection of surge protective devices from all major manufacturers. Contact our team at 800-232-5809 for pricing and technical support.</p>','["surge protection","spd","type 1+2","eaton","208y/120v","lightning protection"]','','','');
