INSERT INTO "products" VALUES(1051,'Siemens 5000A Switchboard Stub Bus Duct 600V','siemens-5000a-switchboard-stub-bus-duct-600v','BD-SIE-5000-x8p9','','Bus Duct & Busway','Siemens','SW-5000','Reconditioned','','["/images/products/siemens-5000a-switchboard-stub-bus-duct-600v/0.jpg"]','','Switchboard Stub','600V','5000A','Bus Duct','Siemens 5000A switchboard stub bus duct section rated at 600V. Available for immediate shipment.','<h3>Product Overview</h3><p>The Siemens 5000A Switchboard Stub Bus Duct 600V is a switchboard stub busway section designed for efficient power distribution in commercial and industrial facilities. Rated at 5000 amps and 600V, this Siemens bus duct provides a flexible and reliable alternative to traditional cable and conduit systems.</p><h3>Technical Specifications</h3><ul><li><strong>Amperage:</strong> 5000A</li><li><strong>Voltage:</strong> 600V</li><li><strong>Type:</strong> Switchboard Stub</li><li><strong>Manufacturer:</strong> Siemens</li></ul><h3>Applications</h3><p>Bus duct systems are used for high-capacity power distribution in manufacturing plants, data centers, hospitals, and high-rise buildings. They offer easier installation, lower maintenance, and greater flexibility than cable systems.</p><h3>Why Circuit Breaker Sales?</h3><p>We maintain one of the largest inventories of bus duct and busway components in the country. Contact us at 800-232-5809 for availability.</p>','["bus duct","busway","switchboard stub","siemens","5000a","600v","power distribution"]','','','');
