INSERT INTO "products" VALUES(1099,'Eaton 60A Fusible Safety Disconnect Switch 480V','eaton-60a-fusible-safety-disconnect-switch-480v','DS-EAT-60-x8pa','','Disconnect Switches','Eaton','DS-60','New Surplus','','["/images/products/eaton-60a-fusible-safety-disconnect-switch-480v/0.jpg"]','','Fusible','480V','60A','Disconnect Switch','Eaton 60A fusible safety disconnect switch rated at 480V. NEMA rated enclosure. UL listed.','<h3>Product Overview</h3><p>The Eaton 60A Fusible Safety Disconnect Switch 480V provides a safe, visible means of disconnecting electrical equipment for maintenance and emergency shutdowns. This Eaton fusible switch is rated at 60A and 480V.</p><h3>Technical Specifications</h3><ul><li><strong>Amperage:</strong> 60A</li><li><strong>Voltage:</strong> 480V</li><li><strong>Type:</strong> Fusible</li><li><strong>Manufacturer:</strong> Eaton</li></ul><h3>Applications</h3><p>Disconnect switches are required by code at the point of connection for motors, HVAC equipment, machinery, and other electrical loads. They provide a safe disconnect point for maintenance personnel.</p><h3>Why Circuit Breaker Sales?</h3><p>We stock disconnect switches from all major manufacturers in a variety of sizes and configurations. Call 800-232-5809.</p>','["disconnect switch","safety switch","fusible","eaton","60a","480v"]','','','');
